const { WebsocketProvider } = require('y-websocket');
const Y = require('yjs');

const wss = new WebSocket.Server({ port: 1234 });

wss.on('connection', (ws) => {
  const doc = new Y.Doc();
  const provider = new WebsocketProvider('ws://localhost:1234', 'my-roomname', doc);

